with app.app_context():
    for item in PRODUCTS:
        product = Product.query.get(item["id"])
        if not product:
            product = Product(id=item["id"])
            db.session.add(product)
        product.name = item["name"]
        product.category = item["category"]
        product.description = item["description"]
        product.image = item["image"]
        product.has_sizes = True
        product.price_s = item["price_s"]
        product.price_m = item["price_m"]
        product.price_l = item["price_l"]
        if product.stock_s is None: product.stock_s = 20
        if product.stock_m is None: product.stock_m = 20
        if product.stock_l is None: product.stock_l = 20
    db.session.commit()
    print(f"Seeded/updated {len(PRODUCTS)} products successfully.")
